import * as React from "react";

import { DeviceIcon } from "../icons";
import {
  Select,
  SelectContent,
  SelectGroup,
  SelectItem,
  SelectLabel,
  SelectSeparator,
  SelectTrigger,
  SelectValue,
} from "../select";
import { cn } from "../utils/cn";

/* -------------------------------------------------------------------------- */
/*  Types                                                                     */
/* -------------------------------------------------------------------------- */

type Device = {
  /** Unique identifier (deviceid). */
  id: string;
  /** Display name (nickname). */
  name: string;
  /** Optional status — "A" = active. */
  status?: string;
};

type DeviceGroup = {
  /** Unique identifier (groupid). */
  id: string;
  /** Display name (nickname). */
  name: string;
  /** Optional status — "A" = active. */
  status?: string;
};

type DeviceSelectProps = {
  /** List of selectable devices. */
  devices: Device[];
  /** Currently selected device or group id. */
  selectedId?: string;
  /** Called when the user selects a device or group. */
  onSelect: (id: string) => void;
  /**
   * When true, also show device groups in the dropdown.
   * Groups are separated from individual devices.
   */
  showGroups?: boolean;
  /** List of device groups — only rendered when `showGroups` is true. */
  groups?: DeviceGroup[];
  /** Placeholder text when nothing is selected. */
  placeholder?: string;
  /** Show an "All devices" option at the top. Defaults to true. */
  showAllOption?: boolean;
  /** Label for the "All devices" option. */
  allOptionLabel?: string;
  /** Whether the select is disabled. */
  disabled?: boolean;
  className?: string;
};

/* -------------------------------------------------------------------------- */
/*  Constants                                                                 */
/* -------------------------------------------------------------------------- */

const ALL_VALUE = "__all__";

/* -------------------------------------------------------------------------- */
/*  Component                                                                 */
/* -------------------------------------------------------------------------- */

/**
 * A device/device-group selector built on the library `Select` (Radix).
 *
 * Matches the Vue `DevicesV2` / `DevicesAndGroupSelect` pattern:
 * - Optional "All devices" item
 * - Device groups section (when `showGroups` is true)
 * - Individual devices section
 *
 * Uses `SelectPopover` pattern from guidewheel-ui.
 */
function DeviceSelect({
  devices,
  selectedId,
  onSelect,
  showGroups = false,
  groups = [],
  placeholder = "Device",
  showAllOption = true,
  allOptionLabel = "All devices",
  disabled = false,
  className,
}: DeviceSelectProps) {
  const handleValueChange = (value: string) => {
    onSelect(value === ALL_VALUE ? "" : value);
  };

  // Map "" or undefined to ALL_VALUE for Radix (which does not allow empty string values)
  const radixValue = !selectedId ? ALL_VALUE : selectedId;

  const hasGroups = showGroups && groups.length > 0;

  return (
    <div data-slot="device-select" className={cn("inline-block", className)}>
      <Select
        value={radixValue}
        onValueChange={handleValueChange}
        disabled={disabled}
      >
        <SelectTrigger
          data-slot="device-select-trigger"
          className="min-w-[180px]"
        >
          <span className="flex items-center gap-2">
            <DeviceIcon size="sm" className="shrink-0 text-muted-foreground" />
            <SelectValue placeholder={placeholder} />
          </span>
        </SelectTrigger>

        <SelectContent data-slot="device-select-content">
          {showAllOption && (
            <SelectItem value={ALL_VALUE}>{allOptionLabel}</SelectItem>
          )}

          {hasGroups && (
            <>
              {showAllOption && <SelectSeparator />}
              <SelectGroup>
                <SelectLabel>Groups</SelectLabel>
                {groups.map((group) => (
                  <SelectItem key={`group-${group.id}`} value={group.id}>
                    Group: {group.name}
                  </SelectItem>
                ))}
              </SelectGroup>
              <SelectSeparator />
            </>
          )}

          <SelectGroup>
            {hasGroups && <SelectLabel>Devices</SelectLabel>}
            {devices.map((device) => (
              <SelectItem key={device.id} value={device.id}>
                {device.name}
              </SelectItem>
            ))}
          </SelectGroup>
        </SelectContent>
      </Select>
    </div>
  );
}

/* -------------------------------------------------------------------------- */
/*  Exports                                                                   */
/* -------------------------------------------------------------------------- */

export { DeviceSelect };
export type { DeviceSelectProps, Device, DeviceGroup };
